import can
import pytest
import time

MSG_ID_GW_VEHICLE_STATUS = 0xC8
GW_SPEED_SCALE = 0.1
GW_SPEED_MIN = 0.0
GW_SPEED_MAX = 250.0

@pytest.fixture(scope="module")
def can_bus():
    bus = can.Bus(bustype="socketcan", channel="can0", bitrate=500000)
    yield bus
    bus.shutdown()

def collect_messages(bus, arb_id, duration_sec):
    messages = []
    end_time = time.time() + duration_sec
    while time.time() < end_time:
        msg = bus.recv(timeout=0.5)
        if msg and msg.arbitration_id == arb_id:
            messages.append(msg)
    return messages

def decode_gw_speed_raw(msg):
    return msg.data[0] | (msg.data[1] << 8)

def decode_gw_speed_kmh(msg):
    return decode_gw_speed_raw(msg) * GW_SPEED_SCALE

