def test_tc_gw_speed_int_001_scaling(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_GW_VEHICLE_STATUS, 2)
    assert msgs
    for msg in msgs:
        assert decode_gw_speed_kmh(msg) == 10.0

def test_tc_gw_speed_int_002_unit_kmh(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_GW_VEHICLE_STATUS, 2)
    assert msgs
    for msg in msgs:
        assert decode_gw_speed_kmh(msg) == 50.0

def test_tc_gw_speed_int_003_min_value(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_GW_VEHICLE_STATUS, 2)
    assert msgs
    for msg in msgs:
        assert decode_gw_speed_kmh(msg) == GW_SPEED_MIN

def test_tc_gw_speed_int_004_max_value(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_GW_VEHICLE_STATUS, 2)
    assert msgs
    for msg in msgs:
        assert decode_gw_speed_kmh(msg) == GW_SPEED_MAX

def test_tc_gw_speed_int_005_range_protection(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_GW_VEHICLE_STATUS, 2)
    assert msgs
    for msg in msgs:
        speed = decode_gw_speed_kmh(msg)
        assert GW_SPEED_MIN <= speed <= GW_SPEED_MAX

def test_tc_gw_speed_int_006_raw_to_physical(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_GW_VEHICLE_STATUS, 2)
    assert msgs
    for msg in msgs:
        assert decode_gw_speed_kmh(msg) == 123.4

def test_tc_gw_speed_int_007_no_offset(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_GW_VEHICLE_STATUS, 2)
    assert msgs
    for msg in msgs:
        assert decode_gw_speed_raw(msg) * GW_SPEED_SCALE == decode_gw_speed_kmh(msg)
